      CharArray::full(s, n + 1, app(l, cons(0, nil)))
    Ensure
      ((__return == 1 &&
        (exists i, 0 <= i && i + 1 < n && l[i] == l[i + 1])) ||
       (__return == 0 &&
        (forall (i: Z), (0 <= i && i + 1 < n) => l[i] != l[i + 1]))) &&
      CharArray::full(s, n + 1, app(l, cons(0, nil)))
*/
{
    int i = 0;

    while (1) {
        if (s[i] == 0) {
            break;
        }
        if (s[i + 1] == 0) {
            break;
        }
        if (s[i] == s[i + 1]) {
            return 1;
        }
        i++;
    }

    return 0;
}

